CustomField.formula:
IF(
   ISBLANK( Resultado__c ), IMAGE("/Distribuidor/resource/Status_Icons/pending.png","Error",25,25),

   IF( OR( CONTAINS( Resultado__c, "No existe la cuenta originante." ), CONTAINS( Resultado__c, "No existe la variedad o el producto asociado."), CONTAINS(Resultado__c, "Cuenta no Válida" ) ),
      IMAGE("/Distribuidor/resource/Status_Icons/rejected.png","OK",25,25),

      IF( OR( CONTAINS( Resultado__c, "No existe la cuenta destinataria" ), CONTAINS( Resultado__c, "No existe la campaña." ), CONTAINS( Resultado__c, "Ya existe una venta con mismo cuit/variedad/cantidad/campaña" ) ),
         IMAGE("/Distribuidor/resource/Status_Icons/warning.png","OK",25,25),

         IF( CONTAINS( Resultado__c, "OK" ),
            IF( TEXT(Tipo_de_Comprobante__c) = "NC", IMAGE("/Distribuidor/resource/Status_Icons/nc.png","NC",27,27),
               IMAGE("/Distribuidor/resource/Status_Icons/approved.png","OK",25,25)
            ),
            IMAGE("/Distribuidor/resource/Status_Icons/rejected.png","OK",25,25)

         )
      )
   )
)
